 1	import React, { useMemo } from 'react';
 2	
 3	import { MigrationPolicyModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { isEmpty } from '@kubevirt-utils/utils/utils';
 7	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Tooltip } from '@patternfly/react-core';
 9	
10	import { MigrationTableDataLayout } from '../../utils/utils';
11	
12	import { migrationsConfigTooltipFields } from './utils';
13	
14	type TooltipFieldObject = { label: string; value: string };
15	
16	type TooltipObject = { defaultConfig: TooltipFieldObject[]; mpConfig: TooltipFieldObject[] };
17	
18	type MigrationPolicyTooltipProps = {
19	  obj: MigrationTableDataLayout;
20	};
21	
22	const MigrationPolicyTooltip: React.FC<MigrationPolicyTooltipProps> = ({ obj }) => {
23	  const { t } = useKubevirtTranslation();
24	
25	  const { defaultConfig, mpConfig } = useMemo<TooltipObject>(() => {
26	    const mpSpec = obj?.mpObj?.spec;
27	    const defaultConfigurations = obj?.migrationsDefaultConfigurations;
28	    return migrationsConfigTooltipFields.reduce(
29	      (acc, { field, getDisplayText, label }) => {
30	        if (mpSpec?.[field] !== undefined) {
31	          return {
32	            ...acc,
33	            mpConfig: [...acc.mpConfig, { label, value: getDisplayText(mpSpec?.[field]) }],
34	          };
35	        }
36	
37	        if (defaultConfigurations?.[field] !== undefined) {
38	          return {
39	            ...acc,
40	            defaultConfig: [
41	              ...acc.defaultConfig,
42	              { label, value: getDisplayText(defaultConfigurations?.[field]) },
43	            ],
44	          };
45	        }
46	
47	        return acc;
48	      },
49	      {
50	        defaultConfig: [],
51	        mpConfig: [],
52	      },
53	    );
54	  }, [obj]);
55	
56	  return (
57	    <Tooltip
58	      content={
59	        <>
60	          {!isEmpty(mpConfig) && (
61	            <>
62	              <div>
63	                <b>{t('MigrationPolicy values')}</b>
64	              </div>
65	              {mpConfig.map(({ label, value }) => (
66	                <div key={value}>
67	                  {label}: {value}
68	                </div>
69	              ))}
70	            </>
71	          )}
72	          {!isEmpty(defaultConfig) && (
73	            <>
74	              <div>
75	                <b>{t('Default values')}</b>
76	              </div>
77	              {defaultConfig.map(({ label, value }) => (
78	                <div key={value}>
79	                  {label}: {value}
80	                </div>
81	              ))}
82	            </>
83	          )}
84	        </>
85	      }
86	    >
87	      {obj?.vmiObj?.status?.migrationState?.migrationPolicyName ? (
88	        <ResourceLink
89	          groupVersionKind={MigrationPolicyModelGroupVersionKind}
90	          name={obj?.vmiObj?.status?.migrationState?.migrationPolicyName}
91	        />
92	      ) : (
93	        <MutedTextSpan text={t('No MigrationPolicy')} />
94	      )}
95	    </Tooltip>
96	  );
97	};
98	
99	export default MigrationPolicyTooltip;

